#include <stdio.h>

int main() {
    int n, val;

    scanf("%d", &n);

    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    scanf("%d", &val);

    int new_arr[n];
    int new_size = 0;

    for (int i = 0; i < n; i++) {
        if (arr[i] != val) {
            new_arr[new_size] = arr[i];
            new_size++;
        }
    }

    if (new_size == 0) {
        printf("Empty array\n");
    } else {
        for (int i = 0; i < new_size; i++) {
            printf("%d", new_arr[i]);
            if (i < new_size - 1) {
                printf(" ");
            }
        }
        printf("\n");
    }

    return 0;
}
